import os
import boto3

def load_latest_model():
    model_path = os.getenv('MODEL_PATH', '/default/model')
    s3_client = boto3.client('s3')
    
    # Assuming models are stored in an S3 bucket under the 'models' prefix
    response = s3_client.list_objects_v2(Bucket='your-bucket-name', Prefix='models/')
    
    latest_model = None
    latest_date = None
    
    for obj in response.get('Contents', []):
        model_name = obj['Key'].split('/')[-1]
        if model_name.endswith('.pth'):  # Adjust extension as needed
            date_str = model_name.replace('.pth', '').split('_')[-1]
            try:
                date = int(date_str)
                if latest_date is None or date > latest_date:
                    latest_model = obj['Key']
                    latest_date = date
            except ValueError:
                continue
    
    if latest_model:
        s3_client.download_file('your-bucket-name', latest_model, os.path.join(model_path, 'latest_model.pth'))
        print(f"Loaded latest model from {latest_model} to {model_path}")
    else:
        print("No model found")

if __name__ == "__main__":
    load_latest_model()